/**
 * Binary search the transition table to find the UTC offset at a given moment.
 *
 * @param utcSeconds - Unix timestamp in seconds
 * @param timezoneId - IANA timezone identifier
 * @returns { offsetMinutes, isDst } or null if timezone not in embedded data
 */
export function getEmbeddedOffset(
  utcSeconds: number,
  timezoneId: string,
): { offsetMinutes: number; isDst: boolean } | null {
  const transitions = TZ_TRANSITIONS[timezoneId];
  if (!transitions) return null;

  const tripleCount = transitions.length / 3;

  if (tripleCount === 0) {
    const initial = TZ_INITIAL_OFFSETS[timezoneId];
    return initial != null ? { offsetMinutes: initial, isDst: false } : null;
  }

  // Before first transition → use initial offset
  if (utcSeconds < transitions[0]) {
    const initial = TZ_INITIAL_OFFSETS[timezoneId];
    return initial != null ? { offsetMinutes: initial, isDst: false } : null;
  }

  // Binary search: find the last transition at or before utcSeconds
  let lo = 0;
  let hi = tripleCount - 1;
  while (lo < hi) {
    const mid = lo + Math.ceil((hi - lo) / 2);
    if (transitions[mid * 3] <= utcSeconds) {
      lo = mid;
    } else {
      hi = mid - 1;
    }
  }

  return {
    offsetMinutes: transitions[lo * 3 + 1],
    isDst: transitions[lo * 3 + 2] === 1,
  };
}
